/**
 * BFF Entry Card 组件
 * - 显示在 Earnings 页面统计图下方
 * - 多种状态动态文案，渐变色卡片样式
 */

import { useEffect, useCallback } from "react";
import { useNavigate } from "react-router-dom";
import { useBffOverview } from "@/hooks/useBff";
import { getBffOverview } from "@/api/bff";
import { shareBffLink } from "@/utils/bffShare";
import { BFF_LANDING_PATH } from "@/constants/bff";
import EarningsImg from "@/assets/images/bff/earnings-img.png";

interface BffEntryCardProps {
  className?: string;
}

export const BffEntryCard = ({ className = "" }: BffEntryCardProps) => {
  const navigate = useNavigate();
  const { overview, loading, setOverview, setLoading } = useBffOverview();

  // rerender-use-callback: 稳定 fetchOverview 引用，供两个 useEffect 共用
  const fetchOverview = useCallback(async () => {
    setLoading(true);
    try {
      const data = await getBffOverview();
      setOverview(data);
    } catch (error) {
      console.error("[BffEntryCard] Failed to fetch overview:", error);
    } finally {
      setLoading(false);
    }
  }, [setOverview, setLoading]);

  // 进入页面时初始加载，loading 互斥防止重复请求
  useEffect(() => {
    if (!overview && !loading) fetchOverview();
  }, [overview, loading, fetchOverview]);

  if (loading || !overview) {
    return null;
  }

  // 邀请了人但无人完成任务 → 不展示入口
  if (overview.entryStatus === "IN_PROGRESS" && overview.totalInviteCount === 0) {
    return null;
  }

  // 预留动态文案逻辑 - 未来可根据 overview.entryStatus 显示不同文案
  // const getCardContent = (status: BffEntryStatus) => { ... }

  const handleCtaClick = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (overview.entryStatus === "NO_INVITE") {
      const inviteCode = overview.inviteCode || "";
      const inviteUrl = `${window.location.origin}${BFF_LANDING_PATH}?c=${inviteCode}`;

      shareBffLink({
        text: `Earn $${overview.bannerRewardAmount ?? 60} for every friend you invite.`,
        url: inviteUrl,
      });
    } else {
      navigate("/bff-dashboard");
    }
  };

  return (
    <div
      className={`flex items-center gap-3 rounded-[16px] p-4 cursor-pointer ${className}`}
      style={{
        background: "linear-gradient(90deg, #658EFF 0%, #4BCFFF 100%)",
      }}
      onClick={() => navigate("/bff-dashboard")}
    >
      {/* 左侧图标 */}
      <div className="shrink-0 w-[48px] h-[48px] flex items-center justify-center">
        <div
          className="w-[50px] h-[50px] flex items-center justify-center text-[20px]"
          style={{
            background: `url(${EarningsImg}) center/cover no-repeat`,
          }}
        ></div>
      </div>

      {/* 中间动态文案 */}
      <div className="flex-1 min-w-0">
        {/* 标题 */}
        <p className="text-[16px] font-semibold text-white">{overview.content?.title || "💸 Tap here to unlock"}</p>
        {/* 内容 */}
        <p className="text-white text-[15px] font-normal mt-1">
          {overview.content?.subTitle || `$${overview.inviterSignupReward ?? 60} per friend.`}
        </p>
      </div>

      {/* 右侧 CTA 按钮 */}
      <button
        className="shrink-0 flex items-center justify-center w-[85px] h-[36px] bg-white rounded-full"
        onClick={handleCtaClick}
      >
        <span className="text-[14px] font-semibold text-[#5B9FFF] leading-5 whitespace-nowrap">Poke Her</span>
      </button>
    </div>
  );
};
