import { useState, useCallback, useEffect } from "react";
import { useLocation } from "react-router-dom";
import TopBar from "@/components/TopBar";
import WeeklyEarningsChart from "./WeeklyEarningsChart";
import WeeklyEarningsSummary from "./WeeklyEarningsSummary";
import EarningDetailCards from "./EarningDetailCards";
import { BffEntryCard } from "@/components/BffEntryCard";
import { useEarningData } from "../../hooks/useEarningData";
import calendarIcon from "@/assets/images/earnings/ic_weekly_earnings_calendar.svg";
import { bpTrack } from "@/tracking";
import { EventName } from "@/tracking/events";

const INITIAL_WEEK_INDEX = 7;

export default function Earnings() {
  const { weekList, refreshWeek } = useEarningData();
  const [currentWeekIndex, setCurrentWeekIndex] = useState(INITIAL_WEEK_INDEX);
  const [selectedDay, setSelectedDay] = useState(-1);
  const { pathname } = useLocation();

  const currentWeek = weekList[currentWeekIndex];

  // 埋点 + 刷新当前周数据（tab 切回时重新触发）
  useEffect(() => {
    if (pathname !== "/earnings") return;
    bpTrack(EventName.pwa_earnings_page_show);
    bpTrack(EventName.pwa_earnings_page_tab_show);
    refreshWeek(INITIAL_WEEK_INDEX, true);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [pathname]);

  const handleWeekChange = useCallback(
    async (index: number) => {
      // 埋点：日期选择点击
      bpTrack(EventName.pwa_earnings_detail_date_click, {
        date: weekList[index]?.firstWeekDayFormatted,
      });
      setSelectedDay(-1);
      setCurrentWeekIndex(index);
      await refreshWeek(index);
    },
    [refreshWeek, weekList],
  );

  const handleSwipeWeek = useCallback(
    (delta: number) => {
      const nextIndex = currentWeekIndex + delta;
      if (nextIndex < 0 || nextIndex >= weekList.length) return;
      handleWeekChange(nextIndex);
    },
    [currentWeekIndex, weekList.length, handleWeekChange],
  );

  const handleResetDay = useCallback(() => setSelectedDay(-1), []);

  return (
    <div className="h-full bg-surface overflow-y-auto">
      <TopBar showProgress={true} />

      <div className="m-4 p-3.5 rounded-xl bg-white relative animate-page-enter">
        <h2 className="text-base font-bold text-brand-dark mb-2.5 font-[Pangram]">Weekly Earnings</h2>
        <div className="flex items-center gap-2 mb-2">
          <div className="relative inline-flex items-center">
            <img src={calendarIcon} alt="" className="absolute left-2.5 w-3.5 h-3.5 pointer-events-none z-10" />
            <select
              className="pl-8 pr-5 py-1.5 bg-brand-light border-0 rounded-full text-xs font-semibold text-brand-dark appearance-none cursor-pointer focus:outline-none"
              value={currentWeekIndex}
              onChange={(e) => handleWeekChange(parseInt(e.target.value))}
            >
              {weekList.map((week, i) => (
                <option key={i} value={i}>
                  {week.firstWeekDayFormatted} – {week.lastWeekDayFormatted}
                </option>
              ))}
            </select>
            <svg className="absolute right-2 pointer-events-none" width="10" height="6" viewBox="0 0 10 6" fill="none">
              <path
                d="M1 1l4 4 4-4"
                stroke="var(--color-brand-dark)"
                strokeWidth="1.5"
                strokeLinecap="round"
                strokeLinejoin="round"
              />
            </svg>
          </div>
        </div>

        <WeeklyEarningsChart
          list={weekList}
          currentIndex={currentWeekIndex}
          onSelectDay={setSelectedDay}
          onResetDay={handleResetDay}
          onSwipeWeek={handleSwipeWeek}
        />

        {currentWeek ? <WeeklyEarningsSummary data={currentWeek} selectedDay={selectedDay} /> : null}
      </div>

      {/* BFF 裂变入口卡片 — 统计图下方 */}
      <div className="mx-4 mb-6">
        <BffEntryCard />
      </div>

      <EarningDetailCards />

      <div className="h-8" />
    </div>
  );
}
